When you terminate a topic and then subscribe, MessageListener.reachedEndOfTopic is called two times.

There is a unit test that reproduces the issue:

```
    @Test
    public void testDoubledReachedEndOfTopic() throws Exception
    {
        String topicName = "persistent://test-prop/vv/ns1/test-" + UUID.randomUUID();
        PulsarClient pulsarClient = PulsarClient.create("pulsar://vv:6650");

        Producer producer = pulsarClient.createProducer(topicName);
        producer.close();

        PulsarAdmin admin = new PulsarAdmin(new URL("http://vv:8080"), new ClientConfiguration());
        admin.persistentTopics().terminateTopicAsync(topicName).get();
        admin.close();

        CountDownLatch latch = new CountDownLatch(2);
        Consumer consumer = pulsarClient.subscribe(topicName, "subscription", new ConsumerConfiguration()
                .setMessageListener(new MessageListener()
                {
                    @Override
                    public void reachedEndOfTopic(Consumer consumer)
                    {
                        System.out.println("reachedEndOfTopic");
                        latch.countDown();
                    }

                    @Override
                    public void received(Consumer consumer, Message message)
                    {
                        // do nothing
                    }
                })
        );

        assertFalse(latch.await(3, TimeUnit.SECONDS));
        assertTrue(latch.getCount() == 1);

        consumer.close();
        pulsarClient.close();
    }
